const results = [];

for (const item of items) {
  const binaryKeys = Object.keys(item.binary || {});

  let attachment_base64, attachment_name, mime_type;

  // Determine client info based on path
  let client_email, client_name;

  if (item.json.client_email) {
    // Tally path — already on item
    client_email = item.json.client_email;
    client_name = item.json.client_name;
  } else {
    // Gmail path — read from Get a message
    const fromData = $('Get a message').first().json.from.value[0];
    client_email = fromData.address;
    client_name = fromData.name || fromData.address;
  }

  if (item.json.attachment_base64) {
    // Tally path
    attachment_base64 = item.json.attachment_base64;
    attachment_name = item.json.attachment_name;
    mime_type = item.json.mime_type;
  } else {
    // Gmail path
    const attachmentKey = binaryKeys[0];
    const binaryData = await this.helpers.getBinaryDataBuffer(items.indexOf(item), attachmentKey);
    attachment_base64 = binaryData.toString('base64');
    attachment_name = item.binary[attachmentKey].fileName;
    mime_type = item.binary[attachmentKey].mimeType;
  }

  results.push({
    json: {
      ...item.json,
      client_email,
      client_name,
      attachment_base64,
      attachment_name,
      mime_type
    }
  });
}

return results;

const results = [];

for (const item of items) {
  const classification = item.json.content[0].text.trim().toLowerCase();

  results.push({
    json: {
      document_type: classification,
      attachment_base64: item.json.attachment_base64,
      attachment_name: item.json.attachment_name
    }
  });
}

return results;

