const results = [];

for (const item of items) {
  const text = item.json.content[0].text;

let client_email, client_name;

if (item.json.client_email) {
  client_email = item.json.client_email;
  client_name = item.json.client_name;
} else {
  try {
    const fromData = $('Get a message').first().json.from.value[0];
    client_email = fromData.address;
    client_name = fromData.name || fromData.address;
  } catch(e) {
    client_email = '';
    client_name = '';
  }
}

  const extract = (tag) => {
    const match = text.match(new RegExp(`<${tag}>(.*?)<\/${tag}>`));
    return match ? match[1].trim() : null;
  };

  const docType = item.json.document_type || $('extract label').all()[items.indexOf(item)].json.document_type;

  const fieldMap = {
    passport: ['full_name', 'passport_number', 'date_of_birth', 'expiry_date', 'nationality'],
    bank_statement: ['account_holder', 'bank_name', 'account_number', 'statement_period', 'closing_balance'],
    proof_of_address: ['full_name', 'address', 'provider', 'statement_date'],
    source_of_funds: ['full_name', 'employment_status', 'business_name', 'annual_income', 'source_description'],
    investment_intake: ['full_name', 'amount_to_invest', 'risk_score', 'risk_classification', 'investment_horizon']
  };

  const fields = fieldMap[docType] || [];
  const extracted = {};
  fields.forEach(f => extracted[f] = extract(f));

  results.push({
    json: {
      document_type: docType,
      attachment_name: item.json.attachment_name,
      client_email,
      client_name,
      extracted
    }
  });
}

return results;

const item = $input.first().json;
const d = { ...item.extracted, ...item };
const issues = [];
let status = 'pass';

// Hard fail checks
if (!d.document_type || d.document_type !== 'passport') {
  issues.push('Document is not a passport');
  status = 'hard_fail';
}
if (d.expiry_date) {
  const expiry = new Date(d.expiry_date);
  const today = new Date();
  if (expiry < today) {
    issues.push(`Passport is expired (expired: ${d.expiry_date})`);
    status = 'hard_fail';
  }
}
if (!d.full_name) {
  issues.push('Full name could not be extracted — document may be unreadable');
  status = 'hard_fail';
}
if (!d.passport_number) {
  issues.push('Passport number missing — document may be unreadable');
  if (status !== 'hard_fail') status = 'hard_fail';
}

// Soft flag checks (only if not already hard_fail)
if (status !== 'hard_fail') {
  if (!d.nationality) {
    issues.push('Nationality field missing — advisor review required');
    status = 'soft_flag';
  }
  if (!d.date_of_birth) {
    issues.push('Date of birth missing — advisor review required');
    status = 'soft_flag';
  }
}

return [{
  json: {
    ...d,
    validation: { status, issues }
  }
}];

const item = $input.first().json;
const d = { ...item.extracted, ...item };
const issues = [];
let status = 'pass';

// Hard fail checks
if (!d.account_holder) {
  issues.push('Account holder name missing — document unreadable or wrong file');
  status = 'hard_fail';
}
if (!d.statement_period) {
  issues.push('Statement period missing — cannot verify recency');
  status = 'hard_fail';
}

if (status !== 'hard_fail') {
  // Check statement is recent (within 3 months)
  if (d.statement_period_end) {
    const endDate = new Date(d.statement_period_end);
    const threeMonthsAgo = new Date();
    threeMonthsAgo.setMonth(threeMonthsAgo.getMonth() - 3);
    if (endDate < threeMonthsAgo) {
      issues.push(`Statement is older than 3 months (period end: ${d.statement_period_end})`);
      status = 'hard_fail';
    }
  }
}

// Soft flag checks
if (status !== 'hard_fail') {
  if (!d.closing_balance) {
    issues.push('Closing balance not found — advisor to verify manually');
    status = 'soft_flag';
  }
  if (d.closing_balance && d.investment_amount) {
    const balance = parseFloat(String(d.closing_balance).replace(/[^0-9.]/g, ''));
    const investment = parseFloat(String(d.investment_amount).replace(/[^0-9.]/g, ''));
    if (!isNaN(balance) && !isNaN(investment) && balance < investment) {
      issues.push(`Closing balance (${d.closing_balance}) is below proposed investment amount (${d.investment_amount})`);
      status = 'soft_flag';
    }
  }
  if (!d.bank_name) {
    issues.push('Bank name not detected — advisor to confirm institution');
    status = 'soft_flag';
  }
}

return [{
  json: {
    ...d,
    validation: { status, issues }
  }
}];

