const d = { ...item.extracted, ...item };
const issues = [];
let status = 'pass';

// Hard fail checks
if (!d.full_name && !d.account_holder_name) {
  issues.push('Name not found on document — unreadable or wrong file submitted');
  status = 'hard_fail';
}
if (!d.address) {
  issues.push('Address could not be extracted');
  status = 'hard_fail';
}
if (!d.statement_date && !d.statement_period_end) {
  issues.push('Document date missing — cannot verify recency');
  status = 'hard_fail';
}

if (status !== 'hard_fail') {
  // Must be within last 3 months
  const rawDate = d.statement_date || d.statement_period_end;
  const docDate = new Date(rawDate);
  const threeMonthsAgo = new Date();
  threeMonthsAgo.setMonth(threeMonthsAgo.getMonth() - 3);
  if (docDate < threeMonthsAgo) {
    issues.push(`Proof of address is older than 3 months (dated: ${rawDate})`);
    status = 'hard_fail';
  }
}

// Soft flag checks
if (status !== 'hard_fail') {
  // Name on address doc vs passport name mismatch (if passport data available)
  const poaName = (d.full_name || d.account_holder_name || '').toLowerCase().trim();
  const passportName = (d.passport_full_name || '').toLowerCase().trim();
  if (passportName && poaName && poaName !== passportName) {
    issues.push(`Name on proof of address (${poaName}) does not match passport name (${passportName})`);
    status = 'soft_flag';
  }
  if (!d.provider) {
    issues.push('Issuing institution not detected — advisor to confirm document source');
    status = 'soft_flag';
  }
}

return [{
  json: {
    ...d,
    validation: { status, issues }
  }
}];

