// Soft flag checks
if (status !== 'hard_fail') {
  const highRiskKeywords = ['crypto', 'cryptocurrency', 'gambling', 'gift', 'loan', 'inheritance'];
  const sourceText = (d.source_description || d.fund_source || '').toLowerCase();
  const flagged = highRiskKeywords.filter(k => sourceText.includes(k));
  if (flagged.length > 0) {
    issues.push(`Source of funds contains elevated-risk terms: ${flagged.join(', ')} — advisor review required`);
    status = 'soft_flag';
  }
  if (!d.annual_income && !d.total_value) {
    issues.push('Annual income or total value not specified — advisor to verify');
    status = 'soft_flag';
  }
  if (!d.supporting_institution) {
    issues.push('Supporting institution or documentation reference not detected');
    if (status === 'pass') status = 'soft_flag';
  }
}

return [{
  json: {
    ...d,
