const item = items[0];
const binaryKeys = Object.keys(item.binary || {});

return binaryKeys.map(key => ({
  json: {
    ...item.json,
    attachmentKey: key
  },
  binary: {
    [key]: item.binary[key]
  }
}));

const allItems = $input.all();

const validations = allItems.map(item => ({
  document_type: item.json.document_type,
  status: item.json.validation?.status || 'hard_fail',
  issues: item.json.validation?.issues || [],
  client_email: item.json.client_email,
  client_name: item.json.client_name,
  extracted: item.json.extracted
}));

const hardFails = validations.filter(v => v.status === 'hard_fail');
const softFlags = validations.filter(v => v.status === 'soft_flag');
const passes = validations.filter(v => v.status === 'pass');

// Decision logic
let decision;
if (hardFails.length > 0) {
  decision = 'failed_submission';
} else if (softFlags.length > 1) {
  decision = 'slight_error';
} else if (softFlags.length === 1) {
  decision = 'approved';
} else {
  decision = 'approved';
}

// Pull client info from first available item
const clientEmail = validations[0]?.client_email;
const clientName = validations[0]?.client_name;

// Build summary per document for email body
const documentSummary = validations.map(v => {
  const issueText = v.issues.length > 0 ? v.issues.join('; ') : 'No issues';
  return `${v.document_type}: ${v.status.toUpperCase()} — ${issueText}`;
});

return [{
  json: {
    decision,
    client_email: clientEmail,
    client_name: clientName,
    total_documents: validations.length,
    hard_fail_count: hardFails.length,
    soft_flag_count: softFlags.length,
    pass_count: passes.length,
    hard_fail_documents: hardFails.map(v => ({ document_type: v.document_type, issues: v.issues })),
    soft_flag_documents: softFlags.map(v => ({ document_type: v.document_type, issues: v.issues })),
    document_summary: documentSummary
  }
}];
